INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('real-estate-moex-01412', 'real-estate', 'real-estate-moex-105-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '甲向乙承租A地耕作，租約未經公證，租期自99年1月28日起至106年1月27日止，而乙於租期內將 系爭A地以60萬元出售予丙，並於101年移轉予丙。乙雖未以書面通知甲行使先買權，然其確曾以口頭 通知甲，而為甲所明確知悉，甲卻故意壓低價格，明示不願以60萬元購買，僅欲以50萬元買受，未行 使先買權，並經證人證實上開情事。甲已知悉系爭買賣條件，待系爭A地價格上漲3倍餘後，以數年前 之價格主張優先承購，有無理由？', '["有理由，因乙違背土地法書面通知先買權的義務在先，故甲仍得主張先買權", "有理由，因乙違背民法書面通知先買權的義務在先，故甲仍得主張先買權", "有理由，因乙違背耕地三七五減租條例書面通知先買權的義務在先，故甲仍得主張先買權", "無理由，因有其他證據證明通知，且縱認通知不生效力，甲如已主張讓與不破租賃，並持續付租金給 丙，則甲先買權的主張已屬權利失效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "062aeebd758a", "answer_pdf_sha1": "7eea5aefad5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01413', 'real-estate', 'real-estate-moex-105-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '平均地權條例對於農業用地之定義，下列敘述何者正確？', '["僅指都市土地農業區、保護區範圍內土地", "指非都市土地或都市土地農業區、保護區範圍內土地，依法供農作、森林、養殖、畜牧及保育使用者", "指非都市土地或都市土地農業區、保護區、風景區範圍內土地，依法供農作使用者", "僅指非都市土地供農作使用者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "062aeebd758a", "answer_pdf_sha1": "7eea5aefad5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01414', 'real-estate', 'real-estate-moex-105-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '甲於105年9月1日將其A屋和其坐落的B地出售於乙。在未有特約的情形，下列敘述何者正確？', '["乙就A屋和B地應繳納奢侈稅", "乙就B地應繳納契稅", "乙就B地應繳納土地增值稅", "乙應繳納印花稅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "062aeebd758a", "answer_pdf_sha1": "7eea5aefad5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01415', 'real-estate', 'real-estate-moex-105-629c9966', 'sub-real-estate-03', NULL, 'single_choice', 'A地及坐落其上之B屋原同屬甲所有。甲僅將B屋贈與並移轉給乙，乙以B屋設定抵押權給丙，其後， 法院拍賣B屋而由丁拍定。下列敘述何者正確？', '["由於法律規定甲乙間就A地視為有地上權關係，故甲得主張先買權", "由於法律推定甲為出租人，故甲得主張先買權", "由於實務上認為強制拍賣在性質上為公法上的買賣，故甲不得主張先買權", "由於物權效力先買權不得任意創設，故甲不得主張先買權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "062aeebd758a", "answer_pdf_sha1": "7eea5aefad5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01416', 'real-estate', 'real-estate-moex-105-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依所得稅法之規定，下列關於土地房屋交易所得稅之敘述，何者正確？', '["交易之房屋、土地係於103年1月1日之次日以後取得，並持有期間少於2年者，應予課徵所得稅", "於103年1月1日之次日後取得依農業發展條例申請興建之農舍，應予課徵所得稅", "交易前無出租、供營業或執行業務使用者，應免納所得稅", "被徵收前先行協議價購之土地及其改良物，應予課徵所得稅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "062aeebd758a", "answer_pdf_sha1": "7eea5aefad5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01417', 'real-estate', 'real-estate-moex-105-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '甲有A地一筆，關於「甲同意A地無償供不特定公眾通行」的資訊，依相關規定與實務見解，下列敘述 何者正確？', '["該資訊屬土地法規定應登記事項，且得登錄於土地參考資訊檔內", "該資訊屬土地法規定應登記事項，但無法登錄於土地參考資訊檔內", "該資訊非屬土地法規定應登記事項，但得登錄於土地參考資訊檔內", "該資訊非屬土地法規定應登記事項，且無法登錄於土地參考資訊檔內"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "062aeebd758a", "answer_pdf_sha1": "7eea5aefad5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01418', 'real-estate', 'real-estate-moex-105-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依相關規定與實務見解，關於地權與地用的敘述，下列何者最正確？', '["甲與乙分別共有A地，則甲出賣其應有部分時，乙有先買權，且該先買權得預先拋棄", "甲將其B基地出租於乙，乙於B地蓋有C屋，則於租賃期間，甲將B地出賣時，乙有先買權，且該先 買權不得預先拋棄", "甲於88年將其D耕地出租於乙，則於租賃期間，甲將D地出賣時，乙有先買權，且該先買權得預先 拋棄", "甲於89年將其E基地出租於乙蓋F屋，約定租賃期間20年，則於105年時，乙請求甲會同申請地上 權登記的權利已消滅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "062aeebd758a", "answer_pdf_sha1": "7eea5aefad5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01419', 'real-estate', 'real-estate-moex-105-629c9966', 'sub-real-estate-03', NULL, 'single_choice', 'A 地原地目為「田」，經所有權人甲申請變更地目為「建」，嗣乙地政事務所認該地目變更係屬違法， 請示丙縣政府如何處理，俟丙決議後，乙乃依丙決議之原則，維持「建」地目之登記，惟於A地之土地 登記簿標示部其他登記事項欄註記：「本土地涉及違法地目變更，土地使用管制仍應受原『田』地目之 限制」，並通知甲。依最高行政法院決議見解，甲如不服該註記，是否得循行政訴訟途徑請求救濟？', '["該註記為行政處分，故甲得提起撤銷訴訟請求救濟", "該註記為行政處分，故甲得提起課予義務訴訟請求救濟", "該註記為事實行為，故甲得提起一般給付訴訟請求救濟", "該註記並非行政處分，故甲不得循行政訴訟途徑請求救濟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "062aeebd758a", "answer_pdf_sha1": "7eea5aefad5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01420', 'real-estate', 'real-estate-moex-105-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '都市計畫法所定義的都市計畫事業，下列何者不包括在內？', '["公共設施建設", "新市鎮建設", "新市區建設", "舊市區更新建設"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "062aeebd758a", "answer_pdf_sha1": "7eea5aefad5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01421', 'real-estate', 'real-estate-moex-105-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '甲於101年5月20日將其A耕地出租於乙。下列敘述何者正確？', '["甲與乙約定該租賃契約租期7年，如未訂立書面契約，則視為不定期限租賃", "租期屆滿後，如乙仍為A地之使用收益，而甲不即表示反對之意思，則視為不定期限繼續契約", "在租賃期間，甲如自願出賣A地於丙，對乙有先買權通知的不真正義務（對己義務、間接義務）", "在租賃期間，法院如拍賣A地而由丙拍定，實務上認為法院對乙有先買權的通知義務，待乙放棄先買 權後，法院始通知丙繳價金"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "062aeebd758a", "answer_pdf_sha1": "7eea5aefad5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
